//! Multi-angle proxy generation for lightweight preview of all angles simultaneously.
//!
//! Generates low-resolution proxy frames for all camera angles, suitable for
//! offline editing, multi-view preview panels, and bandwidth-constrained workflows.
//!
//! Proxy frames are generated by downscaling source frames to a fraction of
//! the original resolution (configurable), with optional quality presets.

use crate::{AngleId, Result, MultiCamError};

/// Quality preset for proxy generation.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ProxyQuality {
    /// Quarter-resolution (1/4 width × 1/4 height). Smallest file size.
    Quarter,
    /// Half-resolution (1/2 width × 1/2 height). Balanced quality.
    Half,
    /// Custom scale factor expressed as a percentage (1–100).
    Custom(u8),
}

impl ProxyQuality {
    /// Return the fractional scale (0.0–1.0) for this preset.
    #[must_use]
    pub fn scale_factor(&self) -> f32 {
        match self {
            Self::Quarter => 0.25,
            Self::Half    => 0.50,
            Self::Custom(pct) => (*pct as f32 / 100.0).clamp(0.01, 1.0),
        }
    }

    /// Compute proxy dimensions for a given source resolution.
    #[must_use]
    pub fn proxy_dimensions(&self, source_width: u32, source_height: u32) -> (u32, u32) {
        let s = self.scale_factor();
        let w = ((source_width as f32 * s).round() as u32).max(1);
        let h = ((source_height as f32 * s).round() as u32).max(1);
        (w, h)
    }
}

/// A single downscaled proxy frame for one camera angle.
#[derive(Debug, Clone)]
pub struct ProxyFrame {
    /// Source angle identifier.
    pub angle: AngleId,
    /// Width of the proxy frame in pixels.
    pub width: u32,
    /// Height of the proxy frame in pixels.
    pub height: u32,
    /// Raw pixel data (grayscale, one byte per pixel).
    pub pixels: Vec<u8>,
    /// Source frame number.
    pub frame_number: u64,
}

impl ProxyFrame {
    /// Number of pixels in this proxy frame.
    #[must_use]
    pub fn pixel_count(&self) -> usize {
        (self.width * self.height) as usize
    }

    /// Return `true` when the pixel buffer length matches the declared dimensions.
    #[must_use]
    pub fn is_valid(&self) -> bool {
        self.pixels.len() == self.pixel_count()
    }
}

/// Configuration for the proxy generator.
#[derive(Debug, Clone)]
pub struct ProxyConfig {
    /// Quality preset controlling the output resolution.
    pub quality: ProxyQuality,
    /// Source frame width in pixels.
    pub source_width: u32,
    /// Source frame height in pixels.
    pub source_height: u32,
    /// Maximum number of angles that will be processed.
    pub angle_count: usize,
}

impl Default for ProxyConfig {
    fn default() -> Self {
        Self {
            quality: ProxyQuality::Quarter,
            source_width: 1920,
            source_height: 1080,
            angle_count: 4,
        }
    }
}

/// Generator that down-samples source frames to proxy resolution for all angles.
///
/// Uses a simple box-filter average to compute each proxy pixel from a
/// `scale × scale` tile of source pixels.  This avoids any external
/// linear-algebra dependencies while producing perceptually reasonable results.
#[derive(Debug)]
pub struct ProxyGenerator {
    config: ProxyConfig,
    /// Proxy dimensions derived from config.
    proxy_width:  u32,
    proxy_height: u32,
}

impl ProxyGenerator {
    /// Create a new `ProxyGenerator` from the given configuration.
    #[must_use]
    pub fn new(config: ProxyConfig) -> Self {
        let (pw, ph) = config
            .quality
            .proxy_dimensions(config.source_width, config.source_height);
        Self {
            config,
            proxy_width: pw,
            proxy_height: ph,
        }
    }

    /// Create with default settings (1920×1080 source, quarter-resolution proxy, 4 angles).
    #[must_use]
    pub fn with_defaults() -> Self {
        Self::new(ProxyConfig::default())
    }

    /// Proxy output width.
    #[must_use]
    pub fn proxy_width(&self) -> u32 {
        self.proxy_width
    }

    /// Proxy output height.
    #[must_use]
    pub fn proxy_height(&self) -> u32 {
        self.proxy_height
    }

    /// Generate a proxy frame for one angle from grayscale `source_pixels`.
    ///
    /// `source_pixels` must contain exactly
    /// `config.source_width × config.source_height` bytes.
    ///
    /// # Errors
    ///
    /// Returns [`MultiCamError::InsufficientData`] when the source buffer is
    /// too small for the declared source dimensions.
    pub fn generate_proxy(
        &self,
        angle: AngleId,
        frame_number: u64,
        source_pixels: &[u8],
    ) -> Result<ProxyFrame> {
        let expected = (self.config.source_width * self.config.source_height) as usize;
        if source_pixels.len() < expected {
            return Err(MultiCamError::InsufficientData(format!(
                "Expected {} bytes for angle {angle} frame {frame_number}, got {}",
                expected,
                source_pixels.len()
            )));
        }

        let pixels = self.downsample(source_pixels);
        Ok(ProxyFrame {
            angle,
            width: self.proxy_width,
            height: self.proxy_height,
            pixels,
            frame_number,
        })
    }

    /// Generate proxies for all angles simultaneously.
    ///
    /// `frames` must contain exactly `config.angle_count` entries, each a
    /// slice of `source_width × source_height` grayscale bytes.
    ///
    /// # Errors
    ///
    /// Returns [`MultiCamError::InvalidAngleCount`] when the number of
    /// provided frames does not match the configured angle count.
    pub fn generate_all_proxies(
        &self,
        frame_number: u64,
        frames: &[&[u8]],
    ) -> Result<Vec<ProxyFrame>> {
        if frames.len() != self.config.angle_count {
            return Err(MultiCamError::InvalidAngleCount(frames.len()));
        }

        frames
            .iter()
            .enumerate()
            .map(|(angle, &src)| self.generate_proxy(angle, frame_number, src))
            .collect()
    }

    // ── internal helpers ─────────────────────────────────────────────────────

    /// Box-filter downscale: each proxy pixel is the mean of the corresponding
    /// tile in the source image.
    fn downsample(&self, src: &[u8]) -> Vec<u8> {
        let sw = self.config.source_width as usize;
        let sh = self.config.source_height as usize;
        let pw = self.proxy_width as usize;
        let ph = self.proxy_height as usize;

        // Scale ratios (source pixels per proxy pixel).
        let x_ratio = sw as f64 / pw as f64;
        let y_ratio = sh as f64 / ph as f64;

        let mut out = Vec::with_capacity(pw * ph);

        for py in 0..ph {
            let src_y0 = (py as f64 * y_ratio) as usize;
            let src_y1 = ((py as f64 + 1.0) * y_ratio) as usize;
            let src_y1 = src_y1.min(sh);

            for px in 0..pw {
                let src_x0 = (px as f64 * x_ratio) as usize;
                let src_x1 = ((px as f64 + 1.0) * x_ratio) as usize;
                let src_x1 = src_x1.min(sw);

                let mut sum = 0u64;
                let mut count = 0u64;

                for sy in src_y0..src_y1 {
                    for sx in src_x0..src_x1 {
                        let idx = sy * sw + sx;
                        if idx < src.len() {
                            sum += src[idx] as u64;
                            count += 1;
                        }
                    }
                }

                let value = if count > 0 { (sum / count) as u8 } else { 0 };
                out.push(value);
            }
        }

        out
    }
}

// ── tests ─────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_proxy_quality_scale_factors() {
        assert!((ProxyQuality::Quarter.scale_factor() - 0.25).abs() < 1e-6);
        assert!((ProxyQuality::Half.scale_factor() - 0.50).abs() < 1e-6);
        assert!((ProxyQuality::Custom(50).scale_factor() - 0.50).abs() < 1e-3);
    }

    #[test]
    fn test_proxy_dimensions() {
        let dims = ProxyQuality::Quarter.proxy_dimensions(1920, 1080);
        assert_eq!(dims, (480, 270));
    }

    #[test]
    fn test_half_proxy_dimensions() {
        let dims = ProxyQuality::Half.proxy_dimensions(1280, 720);
        assert_eq!(dims, (640, 360));
    }

    #[test]
    fn test_proxy_frame_is_valid() {
        let frame = ProxyFrame {
            angle: 0,
            width: 10,
            height: 10,
            pixels: vec![0u8; 100],
            frame_number: 1,
        };
        assert!(frame.is_valid());
    }

    #[test]
    fn test_proxy_frame_invalid_when_wrong_length() {
        let frame = ProxyFrame {
            angle: 0,
            width: 10,
            height: 10,
            pixels: vec![0u8; 50],
            frame_number: 1,
        };
        assert!(!frame.is_valid());
    }

    #[test]
    fn test_generator_dimensions_match_quality() {
        let gen = ProxyGenerator::with_defaults(); // 1920×1080 Quarter
        assert_eq!(gen.proxy_width(), 480);
        assert_eq!(gen.proxy_height(), 270);
    }

    #[test]
    fn test_generate_proxy_uniform_frame() {
        let cfg = ProxyConfig {
            quality: ProxyQuality::Quarter,
            source_width: 8,
            source_height: 8,
            angle_count: 1,
        };
        let gen = ProxyGenerator::new(cfg);
        // 8×8 source all 200 → proxy should also be ~200
        let src = vec![200u8; 64];
        let frame = gen.generate_proxy(0, 0, &src).expect("should succeed");
        assert!(frame.is_valid());
        for &px in &frame.pixels {
            assert_eq!(px, 200, "uniform downscale should preserve pixel value");
        }
    }

    #[test]
    fn test_generate_proxy_too_small_source_errors() {
        let gen = ProxyGenerator::with_defaults();
        let src = vec![0u8; 10]; // way too small
        assert!(gen.generate_proxy(0, 0, &src).is_err());
    }

    #[test]
    fn test_generate_all_proxies() {
        let cfg = ProxyConfig {
            quality: ProxyQuality::Half,
            source_width: 4,
            source_height: 4,
            angle_count: 2,
        };
        let gen = ProxyGenerator::new(cfg);
        let src0 = vec![100u8; 16];
        let src1 = vec![150u8; 16];
        let proxies = gen
            .generate_all_proxies(5, &[src0.as_slice(), src1.as_slice()])
            .expect("should succeed");
        assert_eq!(proxies.len(), 2);
        assert_eq!(proxies[0].angle, 0);
        assert_eq!(proxies[1].angle, 1);
        assert_eq!(proxies[0].frame_number, 5);
    }

    #[test]
    fn test_generate_all_proxies_wrong_count() {
        let cfg = ProxyConfig {
            quality: ProxyQuality::Quarter,
            source_width: 4,
            source_height: 4,
            angle_count: 3,
        };
        let gen = ProxyGenerator::new(cfg);
        let src = vec![0u8; 16];
        assert!(gen.generate_all_proxies(0, &[src.as_slice()]).is_err());
    }
}
